const $=t=>document.getElementById(t),setStatus=(t,e=!1)=>{$("status").textContent=t,$("status").style.color=e?"#b91c1c":"#065f46"},normalizeUrl=t=>{const e=(t||"").trim();return e?e.replace(/\/+$/,""):""},load=async()=>{const{apiUrl:t,webAppUrl:e}=await chrome.storage.sync.get(["apiUrl","webAppUrl"]);$("apiUrl").value=t||"https://Inkverta-api.up.railway.app",$("webAppUrl").value=e||"https://Inkverta.vercel.app"},save=async()=>{const t=normalizeUrl($("apiUrl").value),e=normalizeUrl($("webAppUrl").value);t?(await chrome.storage.sync.set({apiUrl:t,webAppUrl:e}),setStatus("Saved.")):setStatus("API URL is required.",!0)},test=async()=>{setStatus("Testing...");const t=normalizeUrl($("apiUrl").value);if(!t)return setStatus("API URL is required.",!0);try{const e=await fetch(`${t}/api/health`,{method:"GET"});if(!e.ok)throw new Error(`HTTP ${e.status}`);setStatus("Connection OK.")}catch(t){setStatus(`Failed: ${t.message}`,!0)}};document.addEventListener("DOMContentLoaded",async()=>{await load(),$("save").addEventListener("click",()=>save()),$("test").addEventListener("click",()=>test())});